#!/usr/bin/env python3
"""Build INDEX.md: one-line summaries for each corpus document, generated by Claude Haiku.

Usage:
  python scripts/build_index.py
  python scripts/build_index.py --corpus /path/to/corpus
"""
import argparse
import sys
from pathlib import Path

ROOT = Path(__file__).parent.parent
sys.path.insert(0, str(ROOT))

import config
from shared import llm

_SUMMARIZE_SYSTEM = (
    "You are a financial document indexer. "
    "Write a single-line summary (max 120 characters) of the document topic. "
    "Include ticker symbols, key themes, and time period if available. "
    "Output only the summary — no preamble, no punctuation at the end."
)


def _extract_front_matter(content: str) -> tuple[str, str]:
    title, date = "", ""
    if not content.startswith("---"):
        return title, date
    for line in content[3:].split("\n"):
        if line.startswith("title:"):
            title = line.partition(":")[2].strip().strip('"')
        elif line.startswith("date:"):
            date = line.partition(":")[2].strip()
        elif line == "---":
            break
    return title, date


def main() -> None:
    parser = argparse.ArgumentParser(description="Build INDEX.md for the agentic search_index tool")
    parser.add_argument("--corpus", type=Path, default=config.CORPUS_DIR)
    args = parser.parse_args()

    corpus_dir: Path = args.corpus
    if not corpus_dir.exists():
        sys.exit(f"Corpus directory not found: {corpus_dir}")

    files = sorted(corpus_dir.glob("*.md"))
    if not files:
        sys.exit(f"No .md files found in {corpus_dir}")

    print(f"Building index for {len(files)} documents...")
    lines: list[str] = []

    for i, fp in enumerate(files, 1):
        content = fp.read_text(encoding="utf-8")
        title, date = _extract_front_matter(content)
        if not title:
            title = fp.stem

        excerpt = content[:3000]
        response = llm.generate(
            f"Summarize this document in one line:\n\n{excerpt}",
            system=_SUMMARIZE_SYSTEM,
            max_tokens=60,
        )
        summary = next((b.text for b in response.content if b.type == "text"), "").strip()
        summary = summary.replace("\n", " ")

        entry = f"{fp.name} | {title} | {date} | {summary}"
        lines.append(entry)
        print(f"  [{i:>4}/{len(files)}] {fp.name}: {summary[:80]}")

    index_path = config.INDEX_DIR / "INDEX.md"
    index_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    print(f"\nIndex written → {index_path}  ({len(lines)} entries)")


if __name__ == "__main__":
    main()
